import subprocess
from typing import TypedDict, Literal, Optional
from langgraph.graph import StateGraph, END
from langchain_openai import ChatOpenAI
from langchain_core.messages import HumanMessage, AIMessage, SystemMessage

class CodeState(TypedDict):
    task: str
    code: str
    error: Optional[str]
    attempts: int

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

def generate_code(state: CodeState) -> dict:
    messages = [
        SystemMessage(content="Write Python code only. Return just the code, no markdown."),
        HumanMessage(content=state["task"]),
    ]
    if state["error"]:
        messages.append(HumanMessage(
            content=f"The previous code produced this error. Fix it:\n{state['error']}"
        ))
        messages.append(AIMessage(content=state["code"]))

    response = llm.invoke(messages)
    return {"code": response.content, "attempts": state["attempts"] + 1}

def execute_code(state: CodeState) -> dict:
    try:
        result = subprocess.run(
            ["python3", "-c", state["code"]],
            capture_output=True, text=True, timeout=10,
        )
        if result.returncode != 0:
            return {"error": result.stderr.strip()}
        return {"error": None}
    except subprocess.TimeoutExpired:
        return {"error": "Execution timed out."}

def route(state: CodeState) -> Literal["generate", "done"]:
    if state["error"] is None:
        return "done"      # success
    if state["attempts"] >= 3:
        return "done"      # give up after 3 attempts
    return "generate"      # retry with error feedback

graph = StateGraph(CodeState)
graph.add_node("generate", generate_code)
graph.add_node("execute", execute_code)

graph.set_entry_point("generate")
graph.add_edge("generate", "execute")
graph.add_conditional_edges("execute", route, {"generate": "generate", "done": END})

app = graph.compile()
result = app.invoke({
    "task": "Write a Python function that returns the factorial of n=5 and prints it.",
    "code": "",
    "error": None,
    "attempts": 0,
})
print(f"Final code (attempt {result['attempts']}):\n{result['code']}")
print(f"Error: {result['error']}")
